from __future__ import annotationsfrom pathlib import Pathfrom typing import AnyTOOL_ID = "ui_common_tracker_kit"TOOL_NAME = "UI Common Tracker Kit"TOOL_VERSION = "R1M"STATUS_INTERNAL_READY = "INTERNAL_TOOL_DEPLOYED"PUBLIC_DEPLOY_BLOCK_STATUS = "BLOCKED_UNTIL_REAL_REFLEX_BROWSER_RUNTIME_VISUAL_MATCH"ROUTES = ("/dev-tracking", "/cdc-dev-tracker", "/cdc-tracker")RENDER_TYPES = (    "cdc_tracker",    "dev_tracker",    "tracker_ui_common_preview",    "approved_visual_oracle",)def _repo_root(explicit_repo_root: str | Path | None = None) -> Path:    if explicit_repo_root is not None:        return Path(explicit_repo_root).resolve()    return Path(__file__).resolve().parents[2]def ui_tracker_tool_manifest(repo_root: str | Path | None = None) -> dict[str, Any]:    root = _repo_root(repo_root)    approved_oracle = (        root / "docs" / "dev_tracking" / "visual_oracle" / "APPROVED_TRACKER_PREVIEW.html"    )    deploy_gate_cli = root / "tools" / "ui_tracker_deploy_gate.py"    operator_launcher_cli = root / "tools" / "ui_tracker_operator_launcher.py"    return {        "tool_id": TOOL_ID,        "tool_name": TOOL_NAME,        "tool_version": TOOL_VERSION,        "status": STATUS_INTERNAL_READY,        "routes": list(ROUTES),        "render_types": list(RENDER_TYPES),        "approved_visual_oracle": str(approved_oracle),        "approved_visual_oracle_exists": approved_oracle.exists(),        "operator_entrypoints": {            "deploy_gate_cli": str(deploy_gate_cli),            "operator_launcher_cli": str(operator_launcher_cli),            "approved_visual_oracle": str(approved_oracle),        },        "operator_commands": {            "tool_gate": "python tools/ui_tracker_deploy_gate.py --out <report>/ui_tracker_deploy_gate.json",            "operator_launcher": "python tools/ui_tracker_operator_launcher.py --out <report>/ui_tracker_operator_launcher.json",            "static_oracle_preview": "python -m http.server 3003 --directory docs/dev_tracking/visual_oracle",        },        "public_reflex_deploy_allowed": False,        "public_reflex_deploy_status": PUBLIC_DEPLOY_BLOCK_STATUS,        "release_gate_required_before_public_deploy": [            "approved_visual_oracle_exists",            "real_reflex_browser_runtime_starts",            "real_reflex_browser_visual_match_with_oracle",            "operator_human_approval",        ],        "safety": {            "no_public_deploy": True,            "no_bun_loop": True,            "no_broker": True,            "no_order": True,            "no_sizing": True,            "human_review_required": True,        },    }def manifest_ready(manifest: dict[str, Any]) -> bool:    required_routes = set(ROUTES)    return (        manifest.get("tool_id") == TOOL_ID        and manifest.get("tool_version") == TOOL_VERSION        and manifest.get("status") == STATUS_INTERNAL_READY        and manifest.get("approved_visual_oracle_exists") is True        and required_routes.issubset(set(manifest.get("routes", [])))        and manifest.get("public_reflex_deploy_allowed") is False        and manifest.get("public_reflex_deploy_status") == PUBLIC_DEPLOY_BLOCK_STATUS    )